const email = $input.first().json;
return [{
  json: {
    subject: email.subject || 'No subject',
    body: email.textPlain || email.text || '',
    sender_email: email.from?.value?.[0]?.address || email.from || ''
  }
}];

const groqResponse = $input.first().json;
const senderEmail = $('Extract Email Fields').first().json.sender_email;
const rawContent = groqResponse.choices?.[0]?.message?.content || '{}';

let parsed = {};
try {
  const cleaned = rawContent.replace(/```json?\n?/g, '').replace(/```/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch(e) {
  // Fallback to raw email fields
  const subj = $('Extract Email Fields').first().json.subject;
  const body = $('Extract Email Fields').first().json.body;
  parsed = { title: subj.substring(0, 200), description: body.substring(0, 500), priority: 'medium', due_date: null };
}

return [{ json: { ...parsed, sender_email: senderEmail } }];

const task = $input.first().json?.data;
const parsed = $('Parse & Validate LLM Response').first().json;

const priorityEmoji = { high: '🔴', medium: '🟡', low: '🟢' }[parsed.priority] || '🟡';

return [{ json: { taskTitle: task?.title || parsed.title, priority: parsed.priority, priorityEmoji, taskId: task?.id, dueDate: parsed.due_date } }];
